import{C as i,o as d,c as p,E as t,a2 as o,j as l,a5 as n,a6 as s}from"./chunks/framework.CkaEw-3u.js";const g={class:"reference-parameter-grid reference-parameter-grid-2"},y=JSON.parse('{"title":"Scripting Settings","description":"Enabling Lua scripts, the script text parameter, and execution limits","frontmatter":{"title":"Scripting Settings","description":"Enabling Lua scripts, the script text parameter, and execution limits","pageClass":"reference-page","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-scripting-settings.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Scripting Settings | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Enabling Lua scripts, the script text parameter, and execution limits"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-scripting-settings.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"property":"og:image:type","content":"image/png"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Scripting Settings | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Enabling Lua scripts, the script text parameter, and execution limits"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.png"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/reference/reference-scripting-settings.md","filePath":"en/reference/reference-scripting-settings.md"}'),h={name:"en/reference/reference-scripting-settings.md"},f=Object.assign(h,{setup(m){const a={standardPreset:{image:"/image/inspector_scripting_standard.webp",alt:"Scripting page in a standard preset",label:"Standard preset · Scripting page",sourceWidth:615,sourceHeight:454,top:0,bottom:454},scriptingPreset:{image:"/image/inspector_scripting_preset.webp",alt:"Global page in the Mug Typography Scripting preset",label:"Scripting preset · Global page",sourceWidth:609,sourceHeight:457,top:0,bottom:457}};return(u,e)=>{const c=i("ReferenceOverview"),r=i("InspectorCrop");return d(),p("div",null,[t(c,{eyebrow:"PARAMETER REFERENCE",title:"Scripting Settings",description:"Configure procedural animation control with Lua 5.4 scripts.",items:[{icon:"▤",title:"Inspector",description:"Location in each preset",href:"#inspector-display"},{icon:"🎬",title:"Edit Page",description:"Generator usage notes",href:"#edit-page-usage-notes"},{icon:"⚠️",title:"Limitations",description:"Error behavior and execution limits",href:"#error-behavior-and-execution-limits"}]}),e[0]||(e[0]=o('<p>In the conventional 2D, 3D, and Lite presets, this page appears when <strong>Page</strong> is set to <code>Scripting</code> in the Inspector. In the dedicated <code>Mug Typography Scripting</code> preset, the same settings appear on the <strong>Global</strong> page. For an overview and examples, see <a href="/mug-typography-docs/en/features/feature-scripting.html">Animate with Lua Scripts (Scripting)</a>.</p><div class="info custom-block"><p class="custom-block-title">Mug Typography Scripting preset</p><p>This preset omits Character Settings and Part Settings and is designed to control up to 128 characters and 512 parts from Lua. Global settings and the 3D Camera settings remain available, but Character and Part selection modes, Copy / Paste, and the character/part Randomize controls are hidden.</p></div><h2 id="inspector-display" tabindex="-1">Inspector Display <a class="header-anchor" href="#inspector-display" aria-label="Permalink to &quot;Inspector Display&quot;">​</a></h2><p>In a standard preset, set <strong>Page</strong> to <code>Scripting</code> to access these controls. In the dedicated Mug Typography Scripting preset, the same Scripting group is always displayed directly on the <strong>Global</strong> page.</p>',4)),l("div",g,[t(r,n(s(a.standardPreset)),null,16),t(r,n(s(a.scriptingPreset)),null,16)]),e[1]||(e[1]=o('<h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Script Enabled</strong></td><td>Runs the Lua script in Script Text while rendering. When on, the script is evaluated every frame, so the host frame cache no longer applies.</td><td>OFF</td></tr><tr><td><strong>Script Text</strong></td><td>The Lua 5.4 script to run (multi-line). Define <code>OnInitialize(ctx)</code>, <code>OnPreLayout(ctx)</code>, and/or <code>OnLayout(ctx)</code>.</td><td>An <code>OnLayout</code> skeleton</td></tr><tr><td><strong>Copy Script</strong></td><td>Copies Script Text to the OS clipboard for use in MT Sim or another editor.</td><td>—</td></tr><tr><td><strong>Paste Script</strong></td><td>Replaces Script Text with the text on the OS clipboard. The change can be reverted with the host&#39;s Undo command.</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Develop scripts in the VSCode extension</p><p>The Script Text field is only the delivery point for a script; it offers no editing assistance. We recommend developing and debugging with the bundled VSCode extension, Mug Typography Scripting Simulator (MT Sim), then moving the finished script with Copy Script in MT Sim and Paste Script in the plugin.</p></div><h2 id="what-scripts-can-control" tabindex="-1">What Scripts Can Control <a class="header-anchor" href="#what-scripts-can-control" aria-label="Permalink to &quot;What Scripts Can Control&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Callback</th><th>Writable targets</th></tr></thead><tbody><tr><td><code>OnPreLayout</code></td><td><code>ctx.global</code> (text, font size, tracking, line spacing, alignment, vertical writing, position, rotation, scale, fill, gradient, stroke, shadow, and more), <code>ctx.camera</code> (3D / Scripting presets)</td></tr><tr><td><code>OnLayout</code></td><td><code>ctx.chars[index]</code> / <code>ctx.parts[index]</code> (position, rotation, scale, pivot, individual colors, strokes, shadows, 3D orientation), <code>ctx.bounding_box</code>, <code>ctx.output</code> (Write On)</td></tr></tbody></table><p>Read-only information includes <code>ctx.time</code> (seconds), <code>ctx.frame</code>, <code>ctx.timeline</code> (clip duration and progress), <code>ctx.font</code>, <code>ctx.meta</code> (API level, preset capabilities, limits), and the measured <code>geometry</code> of characters and parts. For the complete specification, see <code>scripting-simulator/docs/scripting_api.md</code> in the distribution ZIP (Japanese).</p><h2 id="edit-page-usage-notes" tabindex="-1">Edit Page Usage Notes <a class="header-anchor" href="#edit-page-usage-notes" aria-label="Permalink to &quot;Edit Page Usage Notes&quot;">​</a></h2><p><strong>Generator presets have limitations when splitting clips or extending them before frame 0.</strong></p><p>These operations can cause DaVinci Resolve to pass incorrect time information, disrupting animations that use <code>ctx.time</code>.</p><p>Avoid these operations, or apply the corresponding Mug Typography preset from Filters to an Adjustment Clip.</p><h2 id="error-behavior-and-execution-limits" tabindex="-1">Error Behavior and Execution Limits <a class="header-anchor" href="#error-behavior-and-execution-limits" aria-label="Permalink to &quot;Error Behavior and Execution Limits&quot;">​</a></h2><p>Script errors never stop rendering. If an error occurs anywhere inside a callback, <strong>all changes made by that callback are discarded</strong> and rendering continues with the original values (per-callback atomicity).</p><table tabindex="0"><thead><tr><th>Failure point</th><th>Result</th></tr></thead><tbody><tr><td>Script load</td><td>The whole script is not executed</td></tr><tr><td><code>OnInitialize</code></td><td>Storage is discarded</td></tr><tr><td><code>OnPreLayout</code></td><td>Renders with the inspector values and also skips <code>OnLayout</code></td></tr><tr><td><code>OnLayout</code></td><td>Renders with the unmodified values generated from the base</td></tr></tbody></table><p>As a runaway guard, each callback invocation is limited to <strong>5,000,000 instructions</strong> and <strong>128 MiB</strong> of memory. Memory is allocated on demand. A callback that exceeds a limit is treated as an error and rolled back as above.</p><div class="warning custom-block"><p class="custom-block-title">Limitations</p><ul><li>Values written by a script only affect that frame&#39;s rendering; they are never written back to the inspector or keyframes</li><li>Script callbacks are skipped while a morph animation is running (during a To Text transformation)</li><li>Rewriting path geometry itself and loading external <code>.lua</code> files are not supported</li></ul></div>',15))])}}});export{y as __pageData,f as default};
